Codeforces Round #731 (Div. 3) A. Shortest Path with Obstacle 判断一下两点最短路径是否为一条直线，障碍是否在该直线上。
#include &lt;bits/stdc++.h&gt;using namespace std; int main() { int t; cin &gt;&gt; t; while(t --){ int x1, y1, x2, y2, xf, yf; cin &gt;&gt; x1 &gt;&gt; y1 &gt;&gt; x2 &gt;&gt; y2 &gt;&gt; xf &gt;&gt; yf; if(x1 == x2 &amp;&amp; x1 == xf &amp;&amp; ((yf &gt;= y1 &amp;&amp; yf &lt;= y2) || (yf &lt;= y1 &amp;&amp; yf &gt;= y2))) cout &lt;&lt; abs(y1 - y2) + 2 &lt;&lt; endl; else if(y1 == y2 &amp;&amp; y1 == yf &amp;&amp; ((xf &gt;= x1 &amp;&amp; xf &lt;= x2) || (xf &lt;= x1 &amp;&amp; xf &gt;= x2))) cout &lt;&lt; abs(x1 - x2) + 2 &lt;&lt; endl; else cout &lt;&lt; abs(x1 - x2) + abs(y1 - y2) &lt;&lt; endl; } return 0; } B. Alphabetical Strings 先找到 a 的位置，然后双指针向两边寻找，如果找不到符合的则输出 NO；
#include &lt;bits/stdc++.h&gt;using namespace std; int main() { int t; cin &gt;&gt; t; while (t--) { string s; cin &gt;&gt; s; int st = -1; for (int i = 0; i &lt; s.size(); i++) if (s[i] == &#39;a&#39;) st = i; if (st == -1) { cout &lt;&lt; &#34;NO&#34; &lt;&lt; endl; continue; } bool flag = true; char now = &#39;b&#39;; for (int l = st - 1, r = st + 1; l &gt;= 0 || r &lt; s.size(); now++) { if (l &gt;= 0 &amp;&amp; s[l] == now) l--; else if (r &lt; s.size() &amp;&amp; s[r] == now) r++; else flag = false; } if (flag) cout &lt;&lt; &#34;YES&#34; &lt;&lt; endl; else cout &lt;&lt; &#34;NO&#34; &lt;&lt; endl; } return 0; } C. Pair Programming 每次添加 a，b数组中可以添加的操作，循环，直到添加完或者出现无法继续添加的情况。
#include &lt;bits/stdc++.h&gt;#define INF 0x3f3f3f3f using namespace std; const int M = 1e5 + 7; int a[M], b[M], ans[M]; int main() { int t; scanf(&#34;%d&#34;, &amp;t); while (t--) { int k, n, m; scanf(&#34;%d%d%d&#34;, &amp;k, &amp;n, &amp;m); for (int i = 1; i &lt;= n; i ++) scanf(&#34;%d&#34;, &amp;a[i]); for (int i = 1; i &lt;= m; i ++) scanf(&#34;%d&#34;, &amp;b[i]); a[n + 1] = b[m + 1] = INF; //数组末尾后一个为INF，方便后面判断  int cnt = 1; for (int i = 1, j = 1; i &lt;= n || j &lt;= m;) { while (i &lt;= n &amp;&amp; a[i] &lt;= k) { ans[cnt ++] = a[i]; if (a[i] == 0) k++; i ++; } while (j &lt;= m &amp;&amp; b[j] &lt;= k) { ans[cnt++] = b[j]; if (b[j] == 0) k++; j ++; } if (a[i] &lt;= k || b[j] &lt;= k) continue; else break; } if (cnt != n + m + 1) printf(&#34;-1\n&#34;); else { for (int i = 1; i &lt;= n + m; i ++) printf(&#34;%d &#34;, ans[i]); printf(&#34;\n&#34;); } } return 0; } D. Co-growing Sequence 寻找两数组直接的关系
#include &lt;bits/stdc++.h&gt;using namespace std; const int M = 2e5 + 7; int num[M], ans[M]; int main() { int t; scanf(&#34;%d&#34;, &amp;t); while (t--) { int n; scanf(&#34;%d&#34;, &amp;n); for (int i = 1; i &lt;= n; i++) scanf(&#34;%d&#34;, &amp;num[i]); int last = num[1]; for (int i = 2; i &lt;= n; i++) { ans[i] = (last | num[i]) ^ num[i]; last = ans[i] ^ num[i]; } for (int i = 1; i &lt;= n; i++) printf(&#34;%d &#34;, ans[i]); printf(&#34;\n&#34;); } return 0; } E. Air Conditioners 优先队列BFS，$O(N)$
#include &lt;bits/stdc++.h&gt;#define x first #define y second using namespace std; typedef pair&lt;int, int&gt; PII; const int M = 3e5 + 7; int a[M], temp[M], ans[M], n, k; bool st[M]; void bfs() { priority_queue&lt;PII, vector&lt;PII&gt;, greater&lt;PII&gt;&gt; heap; for (int i = 1; i &lt;= k; i++) heap.push({temp[i], a[i]}); while (heap.size()) { auto now = heap.top(); heap.pop(); if (st[now.y]) continue; st[now.y] = true; ans[now.y] = now.x; if (now.y &gt; 1) heap.push({now.x + 1, now.y - 1}); if (now.y &lt; n) heap.push({now.x + 1, now.y + 1}); } } int main() { int t; scanf(&#34;%d&#34;, &amp;t); while (t--) { memset(st, 0, sizeof st); scanf(&#34;%d%d&#34;, &amp;n, &amp;k); for (int i = 1; i &lt;= k; i++) scanf(&#34;%d&#34;, &amp;a[i]); for (int i = 1; i &lt;= k; i++) scanf(&#34;%d&#34;, &amp;temp[i]); bfs(); for (int i = 1; i &lt;= n; i++) printf(&#34;%d &#34;, ans[i]); printf(&#34;\n&#34;); } return 0; } F. Array Stabilization (GCD version) 首先寻找整个数组的是否完全相等，算出整个数组的 gcd，每个元素 /= gcd，找到该数组的最长公共质因子就为答案。
#include &lt;bits/stdc++.h&gt;using namespace std; typedef pair&lt;int, int&gt; PII; const int M = 1e6 + 7; int prime[M], cnt, num[M]; bool st[M]; int gcd(int a, int b) { return b ? gcd(b, a % b) : a; } void get_prime(int x) { for (int i = 2; i &lt;= x; i++) { if (!st[i]) prime[cnt++] = i; for (int j = 0; prime[j] &lt;= x / i; j++) { st[prime[j] * i] = true; if (i % prime[j] == 0) break; } } } bool cmp(PII a, PII b) { if (a.first != b.first) return a.first &gt; b.first; else return a.second &lt; b.second; } int main() { get_prime(1e6);//筛一下质数  int t; scanf(&#34;%d&#34;, &amp;t); while (t--) { map&lt;int, int&gt; mp; vector&lt;PII&gt; vec; int n, m = 0, g = 0; scanf(&#34;%d&#34;, &amp;n); bool same = true; for (int i = 1; i &lt;= n; i++) { scanf(&#34;%d&#34;, &amp;num[i]); if (same &amp;&amp; i &gt; 1 &amp;&amp; num[i] != num[i - 1]) same = false; if (!g) g = num[i]; else g = gcd(g, num[i]); m = max(m, num[i]); int now = num[i];//对每一个数进行质因数分解  for (int j = 0; j &lt;= 1e3 &amp;&amp; prime[j] &lt;= now; j++) { if (now % prime[j] == 0) { mp[prime[j]]++; while (now % prime[j] == 0) { now /= prime[j]; } } } if (now != 1) mp[now]++; } if (same) { printf(&#34;0\n&#34;); continue; } for (auto it : mp) { vec.push_back({it.second, it.first}); } sort(vec.begin(), vec.end(), cmp);//按出现次数对质因数排序  for (int i = 1; i &lt;= n; i++) num[i] /= g; int ans = 1, count_num = 0; for (auto it : vec) { if (count_num++ &gt; 1e3 || it.first &lt;= ans) break; int k = 0, now = 0, head = 0; for (int j = 1; j &lt;= n; j++) { if (num[j] % it.second == 0) k++; else { if (num[1] % it.second == 0 &amp;&amp; !head) head = k; now = max(now, k); k = 0; } } if (k) { now = max(now, k + head); } ans = max(ans, now); } cout &lt;&lt; ans &lt;&lt; endl; } return 0; }

AtCoder Beginner Contest 207 A-Repression 水题
#include &lt;iostream&gt;using namespace std; int main() { int a, b, c; cin &gt;&gt; a &gt;&gt; b &gt;&gt; c; int ans = max(a + b, b + c); ans = max(a + c, ans); cout &lt;&lt; ans &lt;&lt; endl; return 0; } B-Hydrate 水题，当$ b \ge C \times D$时无解； 否则设答案为T $$ D \geqslant \frac{A + T \times B}{C \times T} \Rightarrow T \geqslant \frac{A}{D \times C - B} $$ 则输出 $\left \lceil \frac{A}{D \times C - B} \right \rceil $
#include &lt;cmath&gt;#include &lt;iostream&gt; using namespace std; typedef long long ll; int main() { int a, b, c, d; cin &gt;&gt; a &gt;&gt; b &gt;&gt; c &gt;&gt; d; if (b &gt;= c * d) puts(&#34;-1&#34;); else printf(&#34;%lld\n&#34;, (ll)ceil(a / (d * c - b))); return 0; } C-Many Segments 暴力法, 每两段区间直接进行判断 $O(N ^ {2}) $; 对 4 种区间情况，进行了一点小处理
#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;iostream&gt;#define x first #define y second  using namespace std; typedef long long ll; const int M = 2021; typedef pair&lt;int, int&gt; PII; PII num[M]; int t[M]; void f(int op, double &amp;a, double &amp;b) { //处理区间开闭  if (op == 2) b -= 0.1; else if (op == 3) a += 0.1; else if (op == 4) { a += 0.1, b -= 0.1; } } bool cheak(int i, int j) { //判断函数  double a = num[i].x, b = num[i].y, c = num[j].x, d = num[j].y; f(t[i], a, b); f(t[j], c, d); if (a &lt;= c &amp;&amp; b &gt;= c) return true; else if (c &lt;= a &amp;&amp; d &gt;= a) return true; return false; } int main() { int n; scanf(&#34;%d&#34;, &amp;n); for (int i = 1; i &lt;= n; i++) scanf(&#34;%d%d%d&#34;, &amp;t[i], &amp;num[i].x, &amp;num[i].y); int cnt = 0; for (int i = 1; i &lt;= n; i++) { for (int j = i + 1; j &lt;= n; j++) { if (cheak(i, j)) { cnt++; } } } printf(&#34;%d\n&#34;, cnt); return 0; } 还可以用离散化 + 扫描线法 ${\large O}(N \log{N}) $; 预处理区间边界，用 map 实现离散化，再扫描线求出答案；
#include &lt;iostream&gt;#include &lt;map&gt;#define x first #define y second  using namespace std; typedef long long ll; const int M = 2021; typedef pair&lt;ll, ll&gt; Pll; typedef pair&lt;int, int&gt; PII; Pll num[M]; int t[M]; void f(int op, ll &amp;a, ll &amp;b) { //处理区间边界  a *= 10, b *= 10; if (op == 2) b -= 1; else if (op == 3) a += 1; else if (op == 4) { a += 1; b -= 1; } } int main() { int n, cnt = 0; scanf(&#34;%d&#34;, &amp;n); map&lt;ll, PII&gt; mp; for (int i = 1; i &lt;= n; i++) { scanf(&#34;%d%lld%lld&#34;, &amp;t[i], &amp;num[i].x, &amp;num[i].y); f(t[i], num[i].x, num[i].y); mp[num[i].x].x++, mp[num[i].y].y++; //记录线段的始，末  } int last = 0; // 当前“延续”的线段  for (auto i : mp) { cnt += last * i.y.x; //计算新出现的与旧的线段的交叉  cnt += (i.y.x - 1) * (i.y.x) / 2;//计算新线段之间的交叉  last += i.y.x - i.y.y; } printf(&#34;%d\n&#34;, cnt); return 0; } 思考：如果是三条线段重叠，则每次更新可能是 $$ \binom{last}{1} \binom{new}{2} + \binom{last}{2}\binom{new}{1} + \binom{new}{3} $$ 依此类推……
E - Mod i #include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;iostream&gt; using namespace std; typedef long long ll; const ll MOD = 1e9 + 7, M = 3030; ll num[M], S[M], dp[M][M], r[M]; int main(){ int N; scanf(&#34;%d&#34;, &amp;N); for (int i = 1; i &lt;= N; i++) scanf(&#34;%lld&#34;, &amp;num[i]); for (int i = 1; i &lt;= N; i++){ S[i] = S[i - 1] + num[i]; } ll ans = 0; dp[0][0] = 1; for (int i = 1; i &lt;= N; i++){ memset(r, 0, sizeof r); for (int j = 0; j &lt;= N; j++){ dp[i][j] = r[S[j] % i]; r[S[j] % i] += dp[i - 1][j]; r[S[j] % i] %= MOD; } ans += dp[i][N]; ans %= MOD; } printf(&#34;%lld\n&#34;, ans); return 0; }
